mkdir -p /tmp_workspace/results && python3 << 'PYEOF'
import json
from datetime import datetime, timezone, timedelta
from zoneinfo import ZoneInfo

# ============================================================
# DATA SETUP
# ============================================================

TZ_SHANGHAI = ZoneInfo("Asia/Shanghai")
TZ_UTC = timezone.utc

def parse_ical_dt(dtstr):
    """Parse iCal datetime string (UTC 'Z' suffix) → datetime (UTC aware)"""
    dtstr = dtstr.strip()
    if dtstr.endswith('Z'):
        return datetime.strptime(dtstr, "%Y%m%dT%H%M%SZ").replace(tzinfo=TZ_UTC)
    # no timezone info - treat as UTC
    return datetime.strptime(dtstr, "%Y%m%dT%H%M%S").replace(tzinfo=TZ_UTC)

def dt_to_ical(dt):
    """Convert aware datetime to iCal UTC string"""
    utc = dt.astimezone(TZ_UTC)
    return utc.strftime("%Y%m%dT%H%M%SZ")

def dt_to_local(dt):
    """Convert to Asia/Shanghai"""
    return dt.astimezone(TZ_SHANGHAI)

# ============================================================
# PARSE EXISTING CALENDAR
# ============================================================

with open('/tmp_workspace/calendar.ics') as f:
    raw_ical = f.read()

# Parse existing events
existing_events = []
in_vevent = False
current_event = {}
for line in raw_ical.splitlines():
    if line.strip() == 'BEGIN:VEVENT':
        in_vevent = True
        current_event = {}
    elif line.strip() == 'END:VEVENT':
        in_vevent = False
        if current_event:
            existing_events.append(current_event)
    elif in_vevent:
        if ':' in line:
            key, val = line.split(':', 1)
            key_base = key.split(';')[0]
            if key_base == 'ATTENDEE':
                if 'ATTENDEE' not in current_event:
                    current_event['ATTENDEE'] = []
                # extract email
                email = val.strip()
                if email.startswith('mailto:'):
                    email = email[7:]
                current_event['ATTENDEE'].append(email)
            else:
                current_event[key_base] = val.strip()

print(f"Parsed {len(existing_events)} existing events")

# Build existing busy schedule: per attendee per day (in Shanghai time)
# attendee_day_meetings: {email: {date_str: [list of (start_utc, end_utc)]}}
attendee_day_meetings = {}

for ev in existing_events:
    start_utc = parse_ical_dt(ev['DTSTART'])
    end_utc = parse_ical_dt(ev['DTEND'])
    start_local = dt_to_local(start_utc)
    day_str = start_local.strftime("%Y-%m-%d")
    attendees = ev.get('ATTENDEE', [])
    for att in attendees:
        if att not in attendee_day_meetings:
            attendee_day_meetings[att] = {}
        if day_str not in attendee_day_meetings[att]:
            attendee_day_meetings[att][day_str] = []
        attendee_day_meetings[att][day_str].append((start_utc, end_utc))

# Print summary per attendee per day
for att in sorted(attendee_day_meetings.keys()):
    for day in sorted(attendee_day_meetings[att].keys()):
        count = len(attendee_day_meetings[att][day])
        print(f"  {att} on {day}: {count} meetings (existing)")

print()
PYEOF

