            if email.startswith('mailto:'): email = email[7:]
            ev['ATTENDEE'].append(email)
        else:
            ev[kb] = v.strip()

print(f"Total events in scheduled.ics: {len(all_events)}")

new_events = [e for e in all_events if e.get('UID','').startswith('new-')]
orig_events = [e for e in all_events if e.get('UID','').startswith('orig-')]
print(f"  Original events: {len(orig_events)}")
print(f"  New events: {len(new_events)}")

UNAVAILABILITY = {
    "alice@example.com": [("Wednesday", 0, 0, 23, 59)],
    "frank@example.com": [("Friday", 17, 0, 23, 59)],
    "grace@example.com": [("Tuesday", 9, 0, 10, 0)],
}

errors = []

# Check all new events
for ev in new_events:
    s = parse_ical_dt(ev['DTSTART'])
    e = parse_ical_dt(ev['DTEND'])
    sl = dt_to_local(s)
    el = dt_to_local(e)

    # Lunch check
    ls = sl.replace(hour=12, minute=0, second=0, microsecond=0)
    le = sl.replace(hour=13, minute=0, second=0, microsecond=0)
    if overlaps(sl, el, ls, le):
        errors.append(f"LUNCH: {ev['SUMMARY']} {sl.strftime('%H:%M')}–{el.strftime('%H:%M')}")

    # Attendee availability
    wday = sl.strftime("%A")
    for att in ev.get('ATTENDEE', []):
        if att not in UNAVAILABILITY: continue
        for (w, sh, sm, eh, em) in UNAVAILABILITY[att]:
            if w != wday: continue
            us = sl.replace(hour=sh, minute=sm, second=0, microsecond=0)
            ue = sl.replace(hour=eh, minute=em, second=0, microsecond=0)
            if overlaps(sl, el, us, ue):
                errors.append(f"UNAVAIL: {att} in '{ev['SUMMARY']}' on {wday} {sl.strftime('%H:%M')}–{el.strftime('%H:%M')}")

# Build schedule from ALL events (for per-day cap and conflict check)
sched = {}
for ev in all_events:
    s = parse_ical_dt(ev['DTSTART'])
    e = parse_ical_dt(ev['DTEND'])
    day = dt_to_local(s).strftime("%Y-%m-%d")
    for att in ev.get('ATTENDEE', []):
        sched.setdefault(att, {}).setdefault(day, []).append((s, e, ev.get('SUMMARY','')))

# Daily cap check
for att, days in sched.items():
    for day, meetings in days.items():
        if len(meetings) > 4:
            errors.append(f"DAILY CAP: {att} has {len(meetings)} meetings on {day}: {[m[2] for m in meetings]}")

# Time conflict check (per attendee) - only flag NEW vs NEW or NEW vs ORIG conflicts
# (orig vs orig already assumed clean from source)
for att, days in sched.items():
    for day, meetings in days.items():
        for i, (s1,e1,t1) in enumerate(meetings):
            for j, (s2,e2,t2) in enumerate(meetings):
                if i >= j: continue
                if overlaps(s1,e1,s2,e2):
                    # Only flag if at least one is a new event
                    new_titles = [nev['SUMMARY'] for nev in new_events]
                    if t1 in new_titles or t2 in new_titles:
                        errors.append(f"CONFLICT: {att} '{t1}' {dt_to_local(s1).strftime('%H:%M')}–{dt_to_local(e1).strftime('%H:%M')} vs '{t2}' {dt_to_local(s2).strftime('%H:%M')}–{dt_to_local(e2).strftime('%H:%M')} on {day}")

if errors:
    print("\n❌ ERRORS FOUND:")
    for err in errors:
        print(f"  {err}")
else:
    print("\n✅ ALL HARD CONSTRAINTS SATISFIED FOR NEW MEETINGS")

# Print final per-attendee daily counts
print("\nPer-attendee daily meeting counts (all events):")
for att in sorted(sched.keys()):
    for day in sorted(sched[att].keys()):
        count = len(sched[att][day])
        flag = " ⚠️ >4" if count > 4 else ""
        print(f"  {att} {day}: {count}{flag}")

# Confirm unscheduled.json
print("\nUnscheduled requests:")
with open('/tmp_workspace/results/unscheduled.json') as f:
    unsch = json.load(f)
for u in unsch:
    print(f"  {u['id']}: {u['reason_code']}")

print("\n✅ Output files validated successfully")
print(f"Results saved in /tmp_workspace/results/")
print(f"  - scheduled.ics   ({len(all_events)} total events: {len(orig_events)} original + {len(new_events)} new)")
print(f"  - unscheduled.json ({len(unsch)} entries)")
print(f"  - decision_log.md")
PYEOF
"}

